[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    public async Task<IActionResult> GetAsync()
    {
        var response = await _httpClient.GetAsync("https://api.example.com/endpoint");
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }

    [HttpPost]
    public async Task<IActionResult> PostAsync([FromBody] string data)
    {
        var content = new StringContent(data, Encoding.UTF8, "text/plain");
        var response = await _httpClient.PostAsync("https://api.example.com/endpoint", content);
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }
}
```

